export interface ZoneFeature {
  zone: number;
  color: string;
  coordinates: number[][][];
}

export interface ProjectedPoint {
  x: number;
  y: number;
}

export class StaticUSMap {
  private container: HTMLElement;
  private canvas: HTMLCanvasElement;
  private markerSvg: SVGSVGElement;
  private ctx: CanvasRenderingContext2D;
  private usClipPath: Path2D;
  private scale: number = 1;
  private offsetX: number = 0;
  private offsetY: number = 0;

  // Geographic bounds matching the SVG map extent
  private readonly bounds = {
    sw: { lng: -124.7, lat: 24.5 },
    ne: { lng: -66.5, lat: 49.5 },
  };

  constructor(container: HTMLElement, _options?: unknown) {
    this.container = container;
    container.style.position = 'relative';
    container.style.overflow = 'hidden';

    // Projection is always calculated against the native SVG dimensions
    this.calculateProjection();

    // --- Layer 1: SVG base map ---
    const svgWrapper = document.createElement('div');
    svgWrapper.style.cssText = `
      position: absolute;
      top: 0; left: 0;
      width: 100%; height: 100%;
      z-index: 1;
      pointer-events: none;
    `;
    svgWrapper.innerHTML = US_MAP_SVG;
    const svgEl = svgWrapper.querySelector('svg');
    if (svgEl) {
      svgEl.style.width = '100%';
      svgEl.style.height = '100%';
      svgEl.style.display = 'block';
    }
    container.appendChild(svgWrapper);

    // --- Layer 2: Zone canvas (transparent, clips to US outline) ---
    this.canvas = document.createElement('canvas');
    this.canvas.width = SVG_WIDTH;
    this.canvas.height = SVG_HEIGHT;
    this.canvas.style.cssText = `
      position: absolute;
      top: 0; left: 0;
      width: 100%; height: 100%;
      z-index: 2;
      pointer-events: none;
    `;
    const ctx = this.canvas.getContext('2d', { alpha: true });
    if (!ctx) throw new Error('Could not get canvas context');
    this.ctx = ctx;
    container.appendChild(this.canvas);

    // Build the Path2D clip shape once — same coordinate space as the canvas (858×560)
    this.usClipPath = new Path2D(US_OUTLINE_PATH);

    // --- Layer 3: Marker SVG (viewBox matches canvas space) ---
    this.markerSvg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    this.markerSvg.setAttribute('viewBox', `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`);
    this.markerSvg.style.cssText = `
      position: absolute;
      top: 0; left: 0;
      width: 100%; height: 100%;
      z-index: 3;
      pointer-events: none;
      overflow: visible;
    `;
    container.appendChild(this.markerSvg);
  }

  // ---------------------------------------------------------------------------
  // Projection: Mercator in radians so X and Y share the same unit scale
  // ---------------------------------------------------------------------------
  private calculateProjection() {
    const lngMinRad = (this.bounds.sw.lng * Math.PI) / 180;
    const lngMaxRad = (this.bounds.ne.lng * Math.PI) / 180;
    const lngRangeRad = lngMaxRad - lngMinRad;

    const mercYMin = this.latToMercatorY(this.bounds.sw.lat);
    const mercYMax = this.latToMercatorY(this.bounds.ne.lat);
    const mercYRange = mercYMax - mercYMin;

    const scaleX = SVG_WIDTH / lngRangeRad;
    const scaleY = SVG_HEIGHT / mercYRange;
    this.scale = Math.min(scaleX, scaleY);

    const projW = lngRangeRad * this.scale;
    const projH = mercYRange * this.scale;

    this.offsetX = (SVG_WIDTH - projW) / 2 - lngMinRad * this.scale;
    this.offsetY = (SVG_HEIGHT - projH) / 2 - mercYMin * this.scale;
  }

  private latToMercatorY(lat: number): number {
    const latRad = (lat * Math.PI) / 180;
    return Math.log(Math.tan(Math.PI / 4 + latRad / 2));
  }

  public project(lng: number, lat: number): ProjectedPoint {
    const lngRad = (lng * Math.PI) / 180;
    const x = lngRad * this.scale + this.offsetX;
    const mercY = this.latToMercatorY(lat);
    const y = SVG_HEIGHT - (mercY * this.scale + this.offsetY);
    return { x, y };
  }

  /** Convert canvas pixel coords back to [lng, lat] */
  public unproject(x: number, y: number): { lng: number; lat: number } {
    const lngRad = (x - this.offsetX) / this.scale;
    const lng = (lngRad * 180) / Math.PI;
    const mercY = (SVG_HEIGHT - y - this.offsetY) / this.scale;
    const latRad = 2 * Math.atan(Math.exp(mercY)) - Math.PI / 2;
    const lat = (latRad * 180) / Math.PI;
    return { lng, lat };
  }

  /** Returns true if the canvas pixel point is inside the US outline */
  public isPointInUS(x: number, y: number): boolean {
    return this.ctx.isPointInPath(this.usClipPath, x, y);
  }

  // ---------------------------------------------------------------------------
  // Zone drawing — clipped to the US outline so colours never bleed outside
  // ---------------------------------------------------------------------------
  public drawZones(zoneFeatures: ZoneFeature[]) {
    this.ctx.clearRect(0, 0, SVG_WIDTH, SVG_HEIGHT);

    this.ctx.save();
    this.ctx.clip(this.usClipPath);

    zoneFeatures.forEach((feature) => {
      this.ctx.fillStyle = feature.color;
      this.ctx.globalAlpha = 0.55;

      feature.coordinates.forEach((ring) => {
        this.ctx.beginPath();
        const start = this.project(ring[0][0], ring[0][1]);
        this.ctx.moveTo(start.x, start.y);
        for (let i = 1; i < ring.length; i++) {
          const pt = this.project(ring[i][0], ring[i][1]);
          this.ctx.lineTo(pt.x, pt.y);
        }
        this.ctx.closePath();
        this.ctx.fill();
      });
    });

    this.ctx.restore();
    this.ctx.globalAlpha = 1.0;
  }

  public clearZones() {
    this.ctx.clearRect(0, 0, SVG_WIDTH, SVG_HEIGHT);
  }

  // ---------------------------------------------------------------------------
  // Warehouse markers
  // ---------------------------------------------------------------------------
  public createWarehouseMarkers(
    warehouses: Warehouse[],
    selectedIds: Set<string>,
    onMarkerClick: (warehouse: Warehouse) => void
  ): Map<string, SVGCircleElement> {
    const existing = this.markerSvg.querySelectorAll('.warehouse-marker');
    existing.forEach((m) => m.remove());

    const markerElements = new Map<string, SVGCircleElement>();

    warehouses.forEach((warehouse) => {
      const pos = this.project(warehouse.coordinates[0], warehouse.coordinates[1]);

      const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
      g.classList.add('warehouse-marker');
      g.setAttribute('data-warehouse-id', warehouse.id);
      g.style.cursor = 'pointer';
      g.style.pointerEvents = 'auto';

      const circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      circle.setAttribute('cx', pos.x.toString());
      circle.setAttribute('cy', pos.y.toString());
      circle.setAttribute('r', '16');
      circle.setAttribute('fill', warehouse.markerColor);
      circle.setAttribute('stroke', 'white');
      circle.setAttribute('stroke-width', '3');
      circle.style.opacity = selectedIds.has(warehouse.id) ? '1' : '0.5';
      circle.style.transition = 'all 0.3s ease';

      const text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
      text.setAttribute('x', pos.x.toString());
      text.setAttribute('y', (pos.y + 5).toString());
      text.setAttribute('text-anchor', 'middle');
      text.setAttribute('fill', 'white');
      text.setAttribute('font-size', '13');
      text.setAttribute('font-weight', 'bold');
      text.style.pointerEvents = 'none';
      text.textContent = warehouse.city.charAt(0);

      g.appendChild(circle);
      g.appendChild(text);
      g.addEventListener('click', () => onMarkerClick(warehouse));

      this.markerSvg.appendChild(g);
      markerElements.set(warehouse.id, circle);
    });

    return markerElements;
  }

  public updateMarkerAppearance(markerId: string, selected: boolean) {
    const marker = this.markerSvg.querySelector(
      `.warehouse-marker[data-warehouse-id="${markerId}"] circle`
    ) as SVGCircleElement | null;

    if (marker) {
      marker.style.opacity = selected ? '1' : '0.5';
      marker.setAttribute('r', selected ? '20' : '16');
    }
  }

  // resize() is a no-op: canvas is fixed at 858×560 internally; CSS scales it
  public resize(_width: number, _height: number) {}

  public destroy() {
    this.canvas.remove();
    this.markerSvg.remove();
  }
}
